import machine
import time
from umqtt.simple import MQTTClient

# Replace with your ESP32's MAC address in hexadecimal format (e.g., '001A2B3C4D5E')
client_id = b'esp32_' + bytes.fromhex('001A2B3C4D5E'.replace(':', ''))

# MQTT broker IP and port
broker_ip = b'192.168.1.1'
broker_port = 1883

# Temperature sensor setup (example: DS18B20)
ds_sensor = machine.ADC(4)

def read_temperature():
    raw_value = ds_sensor.read()
    voltage = raw_value * (3.3 / 4095)
    temperature_c = (voltage - 0.5) * 100
    return temperature_c

client = MQTTClient(client_id, broker_ip, port=broker_port)

def connect_and_publish():
    client.connect()
    while True:
        temp = read_temperature()
        client.publish(b'sensors/temp', str(temp).encode())
        time.sleep(60)  # Publish every minute

try:
    connect_and_publish()
finally:
    client.disconnect()